export type GeneratedScreenDefinition = {
  id: string;
  blueprintCode: string;
  processCode: string;
  stepCode: string;
  actorCode: string;
  audience: "USER" | "ADMIN";
  pageId: string;
  pageName: string;
  routePath: string;
  screenType: string;
  templateCode: string;
  specification: Record<string, unknown>;
  traceability: Record<string, unknown>;
};

// Generated by scripts/generate-screen-blueprints.mjs. Do not hand-edit.
export const GENERATED_SCREEN_CATALOG: readonly GeneratedScreenDefinition[] = [];

export function findGeneratedScreen(pathname: string) {
  const normalized = pathname.replace(/^\/en(?=\/)/, "") || "/";
  return GENERATED_SCREEN_CATALOG.find((screen) => screen.routePath === normalized);
}
